public boolean ifMatchFixedFilter(String apname, String path, String sheet, int rootNodeId, User user, RagicBundle bundle, boolean isMVP, String[] filterV2) {
    if(apname == null || apname.trim().isEmpty() ||
       path == null || path.trim().isEmpty() ||
       sheet == null || sheet.trim().isEmpty() ||
       rootNodeId == Const.NONODE) return false;

    NUIForm listingPage = AppManager.getListingPage(apname, path, sheet,true);
    NUIForm formPage = AppManager.getFormPage(apname, path, sheet,true);
    if(listingPage==null) return false;

    List<NUIFilter> fixedFilters = listingPage.getFixedFilters();
    if((fixedFilters == null || fixedFilters.size() == 0) && (!isMVP || filterV2 == null)) return true;

    APIQuery q = new APIQuery(apname, path, sheet);
    q.setUpdateMode();
    if(fixedFilters != null) {
      for (NUIFilter fixedFilter : fixedFilters) {
        for (int fixedFilterDomain : fixedFilter.getDomainIds())
            q.addFetchDomains(fixedFilterDomain); // for performance
      }
    }

    NUIFilterSet fset = new NUIFilterSet();
    if(fixedFilters != null) {
      for (NUIFilter fixedFilter : fixedFilters) {
        fset.addFilter(fixedFilter);
      }
    }

    if(isMVP && filterV2 != null && filterV2.length > 0) {
        q.addFetchDomains(formPage.getTitleField());

        //apply filters on the mvp block now
        for (String s : filterV2) {
          NUIFilter filter = listingPage.createNUIFilterV2(s);
          if (filter == null) continue;
          fset.addFilter(filter);
          for (int filterDomain : filter.getDomainIds()) {
              q.addFetchDomains(filterDomain); // for performance
          }
          q.addFetchDomains(filter.getOriginalDomainId());
        }
    }

    APIEntry e = q.getAPIEntry(rootNodeId);
    if(e == null) return false;

    return e.checkFilterSet(fset, user, bundle);
}

